你可以创建一个名为Input的类，并在其内部实现按键的检测。在SDL库中，可以使用SDL_GetKeyboardState函数来获取当前按键的状态。以下是一个示例代码：

```cpp
#include <SDL.h>

class Input {
public:
    Input() {
        currentKeyboardState = SDL_GetKeyboardState(&numKeys);
        previousKeyboardState = new Uint8[numKeys];
        memcpy(previousKeyboardState, currentKeyboardState, numKeys);
    }

    ~Input() {
        delete[] previousKeyboardState;
    }

    bool IsKeyPressed(SDL_Scancode scancode) {
        return currentKeyboardState[scancode] && !previousKeyboardState[scancode];
    }

    void Update() {
        memcpy(previousKeyboardState, currentKeyboardState, numKeys);
        currentKeyboardState = SDL_GetKeyboardState(NULL);
    }

private:
    int numKeys;
    const Uint8* currentKeyboardState;
    Uint8* previousKeyboardState;
};
```

在main函数中使用该类的示例：

```cpp
int main() {
    SDL_Init(SDL_INIT_VIDEO);

    SDL_Window* window = SDL_CreateWindow("Test", SDL_WINDOWPOS_UNDEFINED, SDL_WINDOWPOS_UNDEFINED, 800, 600, SDL_WINDOW_SHOWN);
    SDL_Renderer* renderer = SDL_CreateRenderer(window, -1, 0);

    Input input;

    bool isRunning = true;

    while (isRunning) {
        SDL_Event event;
        while (SDL_PollEvent(&event)) {
            if (event.type == SDL_QUIT) {
                isRunning = false;
            }
        }

        input.Update();

        if (input.IsKeyPressed(SDL_SCANCODE_SPACE)) {
            // Space key is pressed
        }

        SDL_RenderClear(renderer);
        SDL_RenderPresent(renderer);
    }

    SDL_DestroyRenderer(renderer);
    SDL_DestroyWindow(window);
    SDL_Quit();

    return 0;
}
```

在主循环中，调用input.Update()函数来更新键盘状态，并通过input.IsKeyPressed函数来检查特定按键是否按下。

